// 解析 AI Agent 响应
const response = $input.first()?.json || {};

// 提取内容
let content = '';
if (response?.output) {
  content = typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
} else if (response?.text) {
  content = response.text;
}

// 尝试解析 JSON
let result = {
  status: 'success',
  background: '',
  roles: {},
  raw: content
};

// 清理可能有的 markdown 代码块
content = content.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '').trim();

try {
  const json = JSON.parse(content);

  if (json.background && json.roles) {
    result.background = json.background;
    result.roles = json.roles;
  } else if (json.state || json.cities || json.background || json.roles) {
    result.background = json.background || json.state || json.scene || '';

    if (json.cities && Array.isArray(json.cities)) {
      const roleMap = {};
      json.cities.forEach(item => {
        const match = String(item).match(/^([a-zA-Z]+)(.+)$/);
        if (match) {
          roleMap[match[1].toLowerCase()] = match[2].trim();
        }
      });
      result.roles = roleMap;
    } else if (json.roles) {
      result.roles = json.roles;
    }
  }
} catch (e) {
  result.raw = content;
}

return [{ json: result }];
